import pytest

def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}

class TestZipDicts:

    def test_happy_path(self):
        dict1 = {'a': 1, 'b': 2}
        dict2 = {'b': 3, 'c': 4}
        expected = {'a': [1, None], 'b': [2, 3], 'c': [None, 4]}
        assert zip_dicts(dict1, dict2) == expected

    def test_empty_dicts(self):
        assert zip_dicts({}, {}) == {}

    def test_one_empty_dict(self):
        dict1 = {'a': 1}
        assert zip_dicts(dict1, {}) == {'a': [1, None]}
        assert zip_dicts({}, dict1) == {'a': [None, 1]}

    def test_no_dicts(self):
        assert zip_dicts() == {}

    def test_multiple_dicts(self):
        dict1 = {'a': 1, 'b': 2}
        dict2 = {'b': 3, 'c': 4}
        dict3 = {'a': 5, 'd': 6}
        expected = {'a': [1, None, 5], 'b': [2, 3, None], 'c': [None, 4, None], 'd': [None, None, 6]}
        assert zip_dicts(dict1, dict2, dict3) == expected

    def test_dicts_with_same_keys(self):
        dict1 = {'a': 1, 'b': 2}
        dict2 = {'a': 3, 'b': 4}
        expected = {'a': [1, 3], 'b': [2, 4]}
        assert zip_dicts(dict1, dict2) == expected

    def test_dicts_with_none_values(self):
        dict1 = {'a': None, 'b': 2}
        dict2 = {'b': 3, 'c': None}
        expected = {'a': [None, None], 'b': [2, 3], 'c': [None, None]}
        assert zip_dicts(dict1, dict2) == {'a': [None, None], 'b': [2, 3], 'c': [None, None]}

    def test_dicts_with_different_data_types(self):
        dict1 = {'a': 1, 'b': "hello"}
        dict2 = {'b': 3.14, 'c': True}
        expected = {'a': [1, None], 'b': ['hello', 3.14], 'c': [None, True]}
        assert zip_dicts(dict1, dict2) == expected

    def test_dicts_with_empty_string_values(self):
        dict1 = {'a': "", 'b': 2}
        dict2 = {'b': 3, 'c': ""}
        expected = {'a': ['', None], 'b': [2, 3], 'c': [None, '']}
        assert zip_dicts(dict1, dict2) == expected

    def test_dicts_with_zero_values(self):
        dict1 = {'a': 0, 'b': 2}
        dict2 = {'b': 3, 'c': 0}
        expected = {'a': [0, None], 'b': [2, 3], 'c': [None, 0]}
        assert zip_dicts(dict1, dict2) == expected
